(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn33"],{"5e1f":function(n,e,a){"use strict";a.r(e);var u=function(){var n=this,e=n.$createElement,u=n._self._c||e;return u("markdown",{attrs:{source:a("d685")}})},t=[],i=a("2877"),s={},r=Object(i["a"])(s,u,t,!1,null,null,null);r.options.__file="utils.vue";e["default"]=r.exports},d685:function(n,e){n.exports="### 函数整理\n\n开彩结果\n```js\n /**\n  * 规则：\n  * 大： 14 - 27,\n  * 小： 0 - 13，\n  * 单： 奇数\n  * 双： 偶数\n  * 小单： 1、 3、 5、 7、 9、 11、 13.\n  * 小双： 0、 2、 4、 6、 8、 10、 12.\n  * 大单: ：15、 17、 19、 21、 23、 25、 27.\n  * 大双：： 14、 16、 18、 20、 22、 24、 26.\n  */\n $(document).ready(function () {\n   \n   init();\n   \n   // init\n   function init() {\n     var _type = 'bj_history';\n     if (document.referrer.indexOf('bj') > -1) {\n       _type = 'bj_history'\n     } else {\n       _type = 'jnd_history'\n     }\n     // 请求接口\n     $.ajax({\n       type: 'GET',\n       url: 't.php',\n       data: {\n         type: _type\n       },\n       dataType: 'json',\n       success: function (data) {\n         // 初始化\n         render(data);\n       }\n     });\n   }\n   \n   function render(data) {\n     var str = '';\n     data.forEach(function (m) {\n       var list = getTmp(m);\n       str += '<tr>'\n       list.map(function (item, index) {\n         if (index == 0) {\n           str += '<td>' + item + '</td>'\n         } else if (index == 1) {\n           str += '<td class=\"num\">' + item + '</td>'\n         } else {\n           var color = '#ff64ca';\n           if (index == 2 || index == 3) {\n             color = '#ffa35a'\n           } else if (index == 4 || index == 5) {\n             color = '#ff6c8c'\n           } else if (index == 6 || index == 7 || index == 8 || index == 9) {\n             color = '#ff64ca'\n           }\n           str += (item ? '<td style=\"background-color:' + color + '\">' : '<td>') + item + '</td>'\n         }\n       })\n       str += '</tr>'\n     })\n     $('#app').append(str);\n   }\n\n   function getTmp(m) {\n     var a = [];\n     var num = m.val1 + m.val2 + m.val3;\n     // 期号\n     a.push(m.qihao);\n     // 值\n     a.push(num)\n     // 大\n     if (smallBig(num) == '大') {\n       a.push('大');\n     } else {\n       a.push('');\n     }\n     // 小\n     if (smallBig(num) == '小') {\n       a.push('小');\n     } else {\n       a.push('');\n     }\n     // 单\n     if (chk(num) == '单') {\n       a.push('单');\n     } else {\n       a.push('');\n     }\n     // 双\n     if (chk(num) == '双') {\n       a.push('双');\n     } else {\n       a.push('');\n     }\n     // 大单\n     if (bigDan(num) == '大单') {\n       a.push('大单');\n     } else {\n       a.push('');\n     }\n     // 小单\n     if (smallDan(num) == '小单') {\n       a.push('小单');\n     } else {\n       a.push('');\n     }\n     //大双\n     if (bigShuang(num) == '大双') {\n       a.push('大双');\n     } else {\n       a.push('');\n     }\n     //小双\n     if (smallShuang(num) == '小双') {\n       a.push('小双');\n     } else {\n       a.push('');\n     }\n     return a;\n   }\n\n   // 判断大小\n   function smallBig(num) {\n     if (num >= 14 && num <= 27) {\n       return '大';\n     } else if (num >= 0 && num <= 13) {\n       return '小';\n     } else {\n       return ''\n     }\n   }\n\n   // 判断单双 \n   function chk(num) {\n     return ((num % 2 == 0) ? '双' : '单');\n   }\n\n   // 判断小单 \n   function smallDan(num) {\n     var a = [1, 3, 5, 7, 9, 11, 13]\n     return a.indexOf(num) > 0 ? '小单' : ''\n   }\n\n   //判断小双 \n   function smallShuang(num) {\n     var a = [0, 2, 4, 6, 8, 10, 12]\n     return a.indexOf(num) > 0 ? '小双' : ''\n   }\n\n   // 大单\n   function bigDan(num) {\n     var a = [15, 17, 19, 21, 23, 25, 27]\n     return a.indexOf(num) > 0 ? '大单' : ''\n   }\n\n   // 大双\n   function bigShuang(num) {\n     var a = [14, 16, 18, 20, 22, 24, 26]\n     return a.indexOf(num) > 0 ? '大双' : ''\n   }\n\n })\n```"}}]);